import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const o="/images/navi11.png?raw=true",u=JSON.parse('{"title":"11 错误处理，调试和测试","description":"","frontmatter":{},"headers":[],"relativePath":"11/0.md","filePath":"11/0.md","lastUpdated":null}'),i={name:"11/0.md"};function n(s,a,p,_,d,h){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="_11-错误处理-调试和测试" tabindex="-1">11 错误处理，调试和测试 <a class="header-anchor" href="#_11-错误处理-调试和测试" aria-label="Permalink to &quot;11 错误处理，调试和测试&quot;">​</a></h1><p>我们经常会看到很多程序员大部分的&quot;编程&quot;时间都花费在检查bug和修复bug上。无论你是在编写修改代码还是重构系统，几乎都是花费大量的时间在进行故障排除和测试，外界都觉得我们程序员是设计师，能够把一个系统从无做到有，是一项很伟大的工作，而且是相当有趣的工作，但事实上我们每天都是徘徊在排错、调试、测试之间。当然如果你有良好的习惯和技术方案来直面这些问题，那么你就有可能将排错时间减到最少，而尽可能的将时间花费在更有价值的事情上。</p><p>但是遗憾的是很多程序员不愿意在错误处理、调试和测试能力上下工夫，导致后面应用上线之后查找错误、定位问题花费更多的时间。所以我们在设计应用之前就做好错误处理规划、测试用例等，那么将来修改代码、升级系统都将变得简单。</p><p>开发Web应用过程中，错误自然难免，那么如何更好的找到错误原因，解决问题呢？11.1小节将介绍Go语言中如何处理错误，如何设计自己的包、函数的错误处理，11.2小节将介绍如何使用GDB来调试我们的程序，动态运行情况下各种变量信息，运行情况的监控和调试。</p><p>11.3小节将对Go语言中的单元测试进行深入的探讨，并示例如何来编写单元测试，Go的单元测试规则规范如何定义，以保证以后升级修改运行相应的测试代码就可以进行最小化的测试。</p><p>长期以来，培养良好的调试、测试习惯一直是很多程序员逃避的事情，所以现在你不要再逃避了，就从你现在的项目开发，从学习Go Web开发开始养成良好的习惯。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+o+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/10/4.html">第十章总结</a></li><li>下一节: <a href="/11/1.html">错误处理</a></li></ul>',10)])])}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
